#!/usr/bin/env -S npx ts-node -r tsconfig-paths/register
/**
 * Example: Create a Unity Catalog catalog and schema
 *
 * This example demonstrates:
 * - Creating a new catalog
 * - Creating a schema within the catalog
 * - Setting catalog and schema properties
 * - Cleaning up resources
 *
 * Prerequisites:
 * - DATABRICKS_HOST environment variable
 * - Valid authentication (PAT, OAuth M2M, or other)
 * - Unity Catalog enabled workspace
 * - Appropriate permissions to create catalogs
 *
 * Usage:
 *   npx ts-node examples/workspace/catalog/create-catalog-schema.ts
 */

import {WorkspaceClient} from "@databricks/sdk-experimental";

async function main() {
    const client = new WorkspaceClient({});

    const catalogName = `sdk_catalog_${Date.now()}`;
    const schemaName = "example_schema";

    console.log(`Creating catalog: ${catalogName}`);

    try {
        // Create catalog
        const catalog = await client.catalogs.create({
            name: catalogName,
            comment: "Example catalog created by SDK",
            properties: {
                created_by: "databricks-sdk-js",
                purpose: "example",
            },
        });

        console.log(`✓ Catalog created successfully`);
        console.log(`  Catalog Name: ${catalog.name}`);
        console.log(`  Full Name: ${catalog.full_name}`);
        console.log(`  Owner: ${catalog.owner}`);

        // Create schema in the catalog
        console.log(`\nCreating schema: ${catalogName}.${schemaName}`);

        const schema = await client.schemas.create({
            name: schemaName,
            catalog_name: catalogName,
            comment: "Example schema for testing",
            properties: {
                environment: "development",
                created_by: "databricks-sdk-js",
            },
        });

        console.log(`✓ Schema created successfully`);
        console.log(`  Schema Name: ${schema.name}`);
        console.log(`  Full Name: ${schema.full_name}`);
        console.log(`  Catalog: ${schema.catalog_name}`);

        // Get schema details
        const schemaDetails = await client.schemas.get({
            full_name: `${catalogName}.${schemaName}`,
        });

        console.log(`\nSchema Details:`);
        console.log(`  Comment: ${schemaDetails.comment}`);
        console.log(`  Owner: ${schemaDetails.owner}`);
        console.log(
            `  Created At: ${schemaDetails.created_at ? new Date(schemaDetails.created_at).toISOString() : "N/A"}`
        );

        // Cleanup: Delete schema and catalog
        console.log(`\nCleaning up resources...`);

        await client.schemas.delete({
            full_name: `${catalogName}.${schemaName}`,
        });
        console.log(`✓ Schema deleted`);

        await client.catalogs.delete({
            name: catalogName,
            force: true,
        });
        console.log(`✓ Catalog deleted`);
    } catch (error) {
        console.error(`✗ Error:`, error);
        process.exit(1);
    }
}

main();
